function HomeMazeNav({ activeRoute, hoveredProject, onHomeClick, onProjectHover }: HomeMazeNavProps) {
  const shouldRenderProjectHoverRoutes = false

  return (
    <div className="home_maze_nav">
      <svg
        className="home_maze_extension"
        viewBox="0 0 4377 4377"
        fill="none"
        xmlns="http://www.w3.org/2000/svg"
        aria-hidden="true"
      >
        <g
          className={`home_maze_extension_line home_maze_extension_line_profile${
            activeRoute === 'profile' ? ' home_maze_extension_line_active' : ''
          }`}
        >
          <path className="home_maze_extension_path_base" d="M1035 780L300 420L-1790 420" pathLength="1" />
          <path className="home_maze_extension_path_progress" d="M1035 780L300 420L-1790 420" pathLength="1" />
          <circle className="home_maze_extension_start" cx="1035" cy="780" r="54" />
          <circle className="home_maze_extension_end" cx="-1790" cy="420" r="54" />
        </g>

        <g
          className={`home_maze_extension_line home_maze_extension_line_work${
            activeRoute === 'work' ? ' home_maze_extension_line_active' : ''
          }`}
        >
          <path className="home_maze_extension_path_base" d="M680 2490L-55 3279L-1990 3279" pathLength="1" />
          <path className="home_maze_extension_path_progress" d="M680 2490L-55 3279L-1990 3279" pathLength="1" />
          <circle className="home_maze_extension_start" cx="680" cy="2490" r="54" />
          <circle className="home_maze_extension_end" cx="-1990" cy="3279" r="54" />
        </g>

        <g
          className={`home_maze_extension_line home_maze_extension_line_contact${
            activeRoute === 'contact' ? ' home_maze_extension_line_active' : ''
          }`}
        >
          <path
            className="home_maze_extension_path_base"
            d="M2278 3450L4568 3440L5065 3668L6195 3646"
            pathLength="1"
          />
          <path
            className="home_maze_extension_path_progress"
            d="M2278 3450L4568 3440L5065 3668L6195 3646"
            pathLength="1"
          />
          <circle className="home_maze_extension_start" cx="2278" cy="3450" r="54" />
          <circle className="home_maze_extension_end" cx="6195" cy="3646" r="54" />
        </g>

        <g className="home_project_dot_layer">
          {shouldRenderProjectHoverRoutes
            ? (['gunit', 'simmons', 'stanley', 'camping'] as const).map((project) => (
                <ProjectHoverRoute
                  key={project}
                  {...projectHoverRoutes[project]}
                  isHovered={hoveredProject === project}
                  project={project}
                />
              ))
            : null}
          <circle
            className={`home_project_dot home_project_dot_simmons${
              hoveredProject === 'simmons' ? ' home_project_dot_hovered' : ''
            }`}
            cx="1990"
            cy="375"
            data-dot-name="simmons"
            r="34"
          />
          <circle
            className="home_project_hit home_project_hit_simmons"
            cx="1990"
            cy="375"
            data-dot-name="simmons-hit"
            onMouseEnter={() => onProjectHover('simmons')}
            onMouseLeave={() => onProjectHover(null)}
            onPointerEnter={() => onProjectHover('simmons')}
            onPointerLeave={() => onProjectHover(null)}
            r="180"
          />
          <circle
            className={`home_project_dot home_project_dot_gunit${
              hoveredProject === 'gunit' ? ' home_project_dot_hovered' : ''
            }`}
            cx="385"
            cy="2118"
            data-dot-name="gunit"
            r="34"
          />
          <circle
            className="home_project_hit home_project_hit_gunit"
            cx="385"
            cy="2118"
            data-dot-name="gunit-hit"
            onMouseEnter={() => onProjectHover('gunit')}
            onMouseLeave={() => onProjectHover(null)}
            onPointerEnter={() => onProjectHover('gunit')}
            onPointerLeave={() => onProjectHover(null)}
            r="180"
          />
          <circle
            className={`home_project_dot home_project_dot_stanley${
              hoveredProject === 'stanley' ? ' home_project_dot_hovered' : ''
            }`}
            cx="2405"
            cy="3682"
            data-dot-name="stanley"
            r="34"
          />
          <circle
            className="home_project_hit home_project_hit_stanley"
            cx="2405"
            cy="3682"
            data-dot-name="stanley-hit"
            onMouseEnter={() => onProjectHover('stanley')}
            onMouseLeave={() => onProjectHover(null)}
            onPointerEnter={() => onProjectHover('stanley')}
            onPointerLeave={() => onProjectHover(null)}
            r="180"
          />
          <circle
            className={`home_project_dot home_project_dot_camping${
              hoveredProject === 'camping' ? ' home_project_dot_hovered' : ''
            }`}
            cx="3198"
            cy="1342"
            data-dot-name="camping"
            r="34"
          />
          <circle
            className="home_project_hit home_project_hit_camping"
            cx="3198"
            cy="1342"
            data-dot-name="camping-hit"
            onMouseEnter={() => onProjectHover('camping')}
            onMouseLeave={() => onProjectHover(null)}
            onPointerEnter={() => onProjectHover('camping')}
            onPointerLeave={() => onProjectHover(null)}
            r="180"
          />
        </g>

        <g className="home_blue_dot_layer">
          <circle
            className="home_blue_dot home_blue_dot_me"
            cx="1126"
            cy="1472"
            data-dot-name="me"
            r="30"
          />
          <circle
            className="home_blue_dot home_blue_dot_favorite"
            cx="3846"
            cy="1358"
            data-dot-name="favorite"
            r="30"
          />
          <circle
            className="home_blue_dot home_blue_dot_attitude"
            cx="3396"
            cy="2488"
            data-dot-name="attitude"
            r="30"
          />
        </g>
        {activeRoute === 'profile' ? (
          <circle
            className="home_destination_bloom home_destination_bloom_profile"
            cx="995"
            cy="700"
            r="34"
          />
        ) : null}
      </svg>
      <HomeLogoLink
        className="home_maze_logo"
        color="#BDBAB6"
        label="Go to home"
        onClick={onHomeClick}
      />
    </div>
  )
}

export default HomeMazeNav
